const p = $input.first().json;
const amountGTQ = (p.amount_cents / 100).toFixed(2);
return [{
  json: {
    subject: `[COMPLIANCE] Prize frozen pending KYC — Q${amountGTQ} GTQ (User ${p.user_id})`,
    body: `A prize credit has been frozen because the winner has not completed KYC verification.

User ID: ${p.user_id}
Prize amount: Q${amountGTQ} GTQ
Trace ID: ${p.trace_id}

The user has been notified to submit their identity documents.
Funds will be released automatically once the compliance team approves the KYC submission.

Admin panel: ${process.env.ADMIN_BASE_URL}/admin/kyc/frozen-balances`
  }
}];
